1	import * as Net from "node:net";
2	
3	import { assert, describe, it } from "@effect/vitest";
4	import { Effect } from "effect";
5	
6	import { NetError, NetService } from "./Net";
7	
8	const closeServer = (server: Net.Server) =>
9	  Effect.sync(() => {
10	    try {
11	      server.close();
12	    } catch {
13	      // Ignore cleanup failures in tests.
14	    }
15	  });
16	
17	const getPort = (server: Net.Server): number => {
18	  const address = server.address();
19	  return typeof address === "object" && address !== null ? address.port : 0;
20	};
21	
22	const openServer = (host?: string): Effect.Effect<Net.Server, NetError> =>
23	  Effect.callback<Net.Server, NetError>((resume) => {
24	    const server = Net.createServer();
25	    let settled = false;
26	
27	    const settle = (effect: Effect.Effect<Net.Server, NetError>) => {
28	      if (settled) return;
29	      settled = true;
30	      resume(effect);
31	    };
32	
33	    server.once("error", (cause) => {
34	      settle(Effect.fail(new NetError({ message: "Failed to open test server", cause })));
35	    });
36	
37	    if (host) {
38	      server.listen(0, host, () => settle(Effect.succeed(server)));
39	    } else {
40	      server.listen(0, () => settle(Effect.succeed(server)));
41	    }
42	
43	    return closeServer(server);
44	  });
45	
46	it.layer(NetService.layer)("NetService", (it) => {
47	  describe("Net helpers", () => {
48	    it.effect("reserveLoopbackPort returns a positive loopback port", () =>
49	      Effect.gen(function* () {
50	        const net = yield* NetService;
51	        const port = yield* net.reserveLoopbackPort();
52	
53	        assert.ok(port > 0);
54	      }),
55	    );
56	
57	    it.effect("isPortAvailableOnLoopback reports false for an occupied port", () =>
58	      Effect.acquireUseRelease(
59	        openServer("127.0.0.1"),
60	        (server) =>
61	          Effect.gen(function* () {
62	            const net = yield* NetService;
63	            const port = getPort(server);
64	
65	            const available = yield* net.isPortAvailableOnLoopback(port);
66	            assert.equal(available, false);
67	          }),
68	        closeServer,
69	      ),
70	    );
71	
72	    it.effect("findAvailablePort returns preferred when it is free", () =>
73	      Effect.gen(function* () {
74	        const net = yield* NetService;
75	        const preferred = yield* net.reserveLoopbackPort();
76	
77	        const resolved = yield* net.findAvailablePort(preferred);
78	        assert.equal(resolved, preferred);
79	      }),
80	    );
81	
82	    it.effect("findAvailablePort falls back when preferred is occupied", () =>
83	      Effect.acquireUseRelease(
84	        openServer(),
85	        (server) =>
86	          Effect.gen(function* () {
87	            const net = yield* NetService;
88	            const preferred = getPort(server);
89	
90	            const resolved = yield* net.findAvailablePort(preferred);
91	            assert.ok(resolved > 0);
92	            assert.notEqual(resolved, preferred);
93	          }),
94	        closeServer,
95	      ),
96	    );
97	  });
98	});
