305	      return thread;
306	    }
307	    return { ...thread, lastVisitedAt: at };
308	  });
309	  return threads === state.threads ? state : { ...state, threads };
310	}
311	
312	export function markThreadUnread(state: AppState, threadId: ThreadId): AppState {
313	  const threads = updateThread(state.threads, threadId, (thread) => {
314	    if (!thread.latestTurn?.completedAt) return thread;
315	    const latestTurnCompletedAtMs = Date.parse(thread.latestTurn.completedAt);
316	    if (Number.isNaN(latestTurnCompletedAtMs)) return thread;
317	    const unreadVisitedAt = new Date(latestTurnCompletedAtMs - 1).toISOString();
318	    if (thread.lastVisitedAt === unreadVisitedAt) return thread;
319	    return { ...thread, lastVisitedAt: unreadVisitedAt };
320	  });
321	  return threads === state.threads ? state : { ...state, threads };
322	}
323	
324	export function toggleProject(state: AppState, projectId: Project["id"]): AppState {
325	  return {
326	    ...state,
327	    projects: state.projects.map((p) => (p.id === projectId ? { ...p, expanded: !p.expanded } : p)),
328	  };
329	}
330	
331	export function setProjectExpanded(
332	  state: AppState,
333	  projectId: Project["id"],
334	  expanded: boolean,
335	): AppState {
336	  let changed = false;
337	  const projects = state.projects.map((p) => {
338	    if (p.id !== projectId || p.expanded === expanded) return p;
339	    changed = true;
340	    return { ...p, expanded };
341	  });
342	  return changed ? { ...state, projects } : state;
343	}
344	
345	export function setError(state: AppState, threadId: ThreadId, error: string | null): AppState {
346	  const threads = updateThread(state.threads, threadId, (t) => {
347	    if (t.error === error) return t;
348	    return { ...t, error };
349	  });
350	  return threads === state.threads ? state : { ...state, threads };
351	}
352	
353	export function setThreadBranch(
354	  state: AppState,
355	  threadId: ThreadId,
356	  branch: string | null,
357	  worktreePath: string | null,
358	): AppState {
359	  const threads = updateThread(state.threads, threadId, (t) => {
360	    if (t.branch === branch && t.worktreePath === worktreePath) return t;
361	    const cwdChanged = t.worktreePath !== worktreePath;
362	    return {
363	      ...t,
364	      branch,
365	      worktreePath,
366	      ...(cwdChanged ? { session: null } : {}),
367	    };
368	  });
369	  return threads === state.threads ? state : { ...state, threads };
370	}
371	
372	// ── Zustand store ────────────────────────────────────────────────────
373	
374	interface AppStore extends AppState {
375	  syncServerReadModel: (readModel: OrchestrationReadModel) => void;
376	  markThreadVisited: (threadId: ThreadId, visitedAt?: string) => void;
377	  markThreadUnread: (threadId: ThreadId) => void;
378	  toggleProject: (projectId: Project["id"]) => void;
379	  setProjectExpanded: (projectId: Project["id"], expanded: boolean) => void;
380	  setError: (threadId: ThreadId, error: string | null) => void;
381	  setThreadBranch: (threadId: ThreadId, branch: string | null, worktreePath: string | null) => void;
382	}
383	
384	export const useStore = create<AppStore>((set) => ({
385	  ...readPersistedState(),
386	  syncServerReadModel: (readModel) => set((state) => syncServerReadModel(state, readModel)),
387	  markThreadVisited: (threadId, visitedAt) =>
388	    set((state) => markThreadVisited(state, threadId, visitedAt)),
389	  markThreadUnread: (threadId) => set((state) => markThreadUnread(state, threadId)),
390	  toggleProject: (projectId) => set((state) => toggleProject(state, projectId)),
391	  setProjectExpanded: (projectId, expanded) =>
392	    set((state) => setProjectExpanded(state, projectId, expanded)),
393	  setError: (threadId, error) => set((state) => setError(state, threadId, error)),
394	  setThreadBranch: (threadId, branch, worktreePath) =>
395	    set((state) => setThreadBranch(state, threadId, branch, worktreePath)),
396	}));
397	
398	// Persist on every state change
399	useStore.subscribe((state) => persistState(state));

