import { useCallback, useEffect, useSyncExternalStore } from "react";
import { getTheme, listThemes, type ThemeDefinition } from "@t3tools/shared/themes";

type Theme = "light" | "dark" | "system";
type ThemeSnapshot = {
  theme: Theme;
  systemDark: boolean;
  colorTheme: string | null;
};

const STORAGE_KEY = "t3code:theme";
const COLOR_THEME_STORAGE_KEY = "t3code:color-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

/**
 * CSS custom properties that are derived from a theme's core colors and applied
 * as inline styles on `<html>`. Keys match the variable names in index.css.
 */
function buildThemeCssProperties(theme: ThemeDefinition): Array<[string, string]> {
  const { colors, mode } = theme;
  const isDark = mode === "dark";

  // Derive the full set of design-system variables from the theme's core tokens
  // so that every Tailwind utility (bg-background, text-foreground, etc.) works.
  return [
    // Core surfaces
    ["--background", colors.background],
    ["--foreground", colors.foreground],
    ["--card", isDark
      ? `color-mix(in srgb, ${colors.background} 98%, #ffffff)`
      : colors.background],
    ["--card-foreground", colors.foreground],
    ["--popover", isDark
      ? `color-mix(in srgb, ${colors.background} 98%, #ffffff)`
      : colors.background],
    ["--popover-foreground", colors.foreground],

    // Brand / interactive
    ["--primary", isDark ? "oklch(0.588 0.217 264)" : "oklch(0.488 0.217 264)"],
    ["--primary-foreground", "#ffffff"],
    ["--secondary", colors.accent],
    ["--secondary-foreground", colors.foreground],

    // Muted / subtle
    ["--muted", colors.accent],
    ["--muted-foreground", isDark
      ? "color-mix(in srgb, #737373 90%, #ffffff)"
      : "color-mix(in srgb, #737373 90%, #000000)"],
    ["--accent", colors.accent],
    ["--accent-foreground", colors.foreground],

    // Semantic
    ["--destructive", isDark
      ? "color-mix(in srgb, #ef4444 90%, #ffffff)"
      : "#ef4444"],
    ["--destructive-foreground", isDark ? "#f87171" : "#b91c1c"],
    ["--info", "#3b82f6"],
    ["--info-foreground", isDark ? "#60a5fa" : "#1d4ed8"],
    ["--success", "#10b981"],
    ["--success-foreground", isDark ? "#34d399" : "#047857"],
    ["--warning", "#f59e0b"],
    ["--warning-foreground", isDark ? "#fbbf24" : "#b45309"],

    // Chrome
    ["--border", isDark ? "rgba(255, 255, 255, 0.06)" : "rgba(0, 0, 0, 0.08)"],
    ["--input", isDark ? "rgba(255, 255, 255, 0.08)" : "rgba(0, 0, 0, 0.10)"],
    ["--ring", isDark ? "oklch(0.588 0.217 264)" : "oklch(0.488 0.217 264)"],

    // Extension tokens
    ["--sidebar", colors.sidebar],
    ["--editor", colors.editor],
    ["--terminal", colors.terminal],
    ["--status-bar", colors.statusBar],
  ];
}

/** All CSS custom property names that `applyThemeColors` may set. */
const THEME_PROPERTY_NAMES = [
  "--background", "--foreground",
  "--card", "--card-foreground",
  "--popover", "--popover-foreground",
  "--primary", "--primary-foreground",
  "--secondary", "--secondary-foreground",
  "--muted", "--muted-foreground",
  "--accent", "--accent-foreground",
  "--destructive", "--destructive-foreground",
  "--info", "--info-foreground",
  "--success", "--success-foreground",
  "--warning", "--warning-foreground",
  "--border", "--input", "--ring",
  "--sidebar", "--editor", "--terminal", "--status-bar",
] as const;

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;
function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): Theme {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredColorTheme(): string | null {
  return localStorage.getItem(COLOR_THEME_STORAGE_KEY);
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark = theme === "dark" || (theme === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

function applyThemeColors(themeId: string | null): void {
  const root = document.documentElement;

  // Clear any previously applied inline theme properties
  for (const prop of THEME_PROPERTY_NAMES) {
    root.style.removeProperty(prop);
  }
  root.style.removeProperty("color-scheme");
  root.style.removeProperty("font-family");
  root.style.removeProperty("font-size");

  if (!themeId) return;

  const theme = getTheme(themeId);
  if (!theme) return;

  // Apply the full set of derived CSS custom properties
  for (const [prop, value] of buildThemeCssProperties(theme)) {
    root.style.setProperty(prop, value);
  }

  root.style.setProperty("color-scheme", theme.mode === "dark" ? "dark" : "light");
  root.style.setProperty("font-family", theme.fontFamily);
  root.style.setProperty("font-size", `${String(theme.fontSize)}px`);
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());
applyThemeColors(getStoredColorTheme());

function getSnapshot(): ThemeSnapshot {
  const theme = getStored();
  const systemDark = theme === "system" ? getSystemDark() : false;
  const colorTheme = getStoredColorTheme();

  if (
    lastSnapshot &&
    lastSnapshot.theme === theme &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.colorTheme === colorTheme
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { theme, systemDark, colorTheme };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    applyThemeColors(getStoredColorTheme());
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY || e.key === COLOR_THEME_STORAGE_KEY) {
      applyTheme(getStored(), true);
      applyThemeColors(getStoredColorTheme());
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

const availableThemes: readonly ThemeDefinition[] = listThemes();

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.theme;
  const colorTheme = snapshot.colorTheme;

  const resolvedTheme: "light" | "dark" =
    theme === "system" ? (snapshot.systemDark ? "dark" : "light") : theme;

  const setTheme = useCallback((next: Theme) => {
    localStorage.setItem(STORAGE_KEY, next);
    localStorage.removeItem(COLOR_THEME_STORAGE_KEY);
    applyTheme(next, true);
    applyThemeColors(null);
    emitChange();
  }, []);

  const setColorTheme = useCallback((themeId: string) => {
    const definition = getTheme(themeId);
    if (!definition) return;
    localStorage.setItem(COLOR_THEME_STORAGE_KEY, themeId);
    localStorage.setItem(STORAGE_KEY, definition.mode);
    applyTheme(definition.mode, true);
    applyThemeColors(themeId);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
    applyThemeColors(colorTheme);
  }, [theme, colorTheme]);

  return { theme, setTheme, resolvedTheme, colorTheme, setColorTheme, availableThemes } as const;
}

