import { type ThemeColors } from "@t3tools/shared/themes";

import { cn } from "~/lib/utils";
import { useTheme } from "~/hooks/useTheme";

function ThemeSwatches({ colors }: { colors: ThemeColors }) {
  const swatches = [
    colors.background,
    colors.foreground,
    colors.accent,
    colors.sidebar,
    colors.editor,
  ];
  return (
    <div className="flex gap-1">
      {swatches.map((color, i) => (
        <span
          key={i}
          className="size-4 rounded-full border border-border/50"
          style={{ backgroundColor: color }}
        />
      ))}
    </div>
  );
}

export function ThemeSelector({ className }: { className?: string }) {
  const { colorTheme, setColorTheme, setTheme, availableThemes } = useTheme();

  return (
    <div className={cn("space-y-2", className)} role="radiogroup" aria-label="Color theme">
      {/* Default option — clears named theme, restores mode-based behavior */}
      <button
        type="button"
        role="radio"
        aria-checked={colorTheme === null}
        className={cn(
          "flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors",
          colorTheme === null
            ? "border-primary/60 bg-primary/8 text-foreground"
            : "border-border bg-background text-muted-foreground hover:bg-accent",
        )}
        onClick={() => setTheme("system")}
      >
        <span className="flex flex-col">
          <span className="text-sm font-medium">Default</span>
          <span className="text-xs">Use the standard light/dark appearance.</span>
        </span>
        {colorTheme === null ? (
          <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Selected
          </span>
        ) : null}
      </button>

      {/* Named themes */}
      {availableThemes.map((theme) => {
        const selected = colorTheme === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={cn(
              "flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            )}
            onClick={() => setColorTheme(theme.id)}
          >
            <span className="flex flex-col gap-1">
              <span className="text-sm font-medium">{theme.name}</span>
              <span className="flex items-center gap-2">
                <span className="text-xs capitalize">{theme.mode} theme</span>
                <ThemeSwatches colors={theme.colors} />
              </span>
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

