  readonly id: string;
  /** Human-readable name shown in the theme picker. */
  readonly name: string;
  /** Controls whether the `.dark` class is applied. */
  readonly mode: ThemeMode;
  /** CSS color values for each surface token. */
  readonly colors: ThemeColors;
  /** CSS `font-family` value. */
  readonly fontFamily: string;
  /** Base font size in pixels. */
  readonly fontSize: number;
}

const DEFAULT_FONT_FAMILY =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';
const DEFAULT_FONT_SIZE = 14;

const t3Dark: ThemeDefinition = {
  id: "t3-dark",
  name: "T3 Dark",
  mode: "dark",
  colors: {
    background: "color-mix(in srgb, #0a0a0a 95%, #ffffff)",
    foreground: "#f5f5f5",
    accent: "rgba(255, 255, 255, 0.04)",
    sidebar: "#111111",
    editor: "#0e0e0e",
    terminal: "#0a0a0a",
    statusBar: "#111111",
  },
  fontFamily: DEFAULT_FONT_FAMILY,
  fontSize: DEFAULT_FONT_SIZE,
};

const t3Light: ThemeDefinition = {
  id: "t3-light",
  name: "T3 Light",
  mode: "light",
  colors: {
    background: "#ffffff",
    foreground: "#262626",
    accent: "rgba(0, 0, 0, 0.04)",
    sidebar: "#f5f5f5",
    editor: "#ffffff",
    terminal: "#fafafa",
    statusBar: "#f5f5f5",
  },
  fontFamily: DEFAULT_FONT_FAMILY,
  fontSize: DEFAULT_FONT_SIZE,
};

const t3Midnight: ThemeDefinition = {
  id: "t3-midnight",
  name: "T3 Midnight",
  mode: "dark",
  colors: {
    background: "#08090d",
    foreground: "#d4d4e0",
    accent: "rgba(130, 150, 255, 0.06)",
    sidebar: "#0c0d14",
    editor: "#0a0b10",
    terminal: "#08090d",
    statusBar: "#0c0d14",
  },
  fontFamily: DEFAULT_FONT_FAMILY,
  fontSize: DEFAULT_FONT_SIZE,
};

const BUILT_IN_THEMES: readonly ThemeDefinition[] = [t3Dark, t3Light, t3Midnight];

export const DEFAULT_THEME_ID = "t3-dark";

export function getTheme(id: string): ThemeDefinition | undefined {
  return BUILT_IN_THEMES.find((t) => t.id === id);
}

export function listThemes(): readonly ThemeDefinition[] {
  return BUILT_IN_THEMES;
}

